def is_private_ip(ip_str):
    """Check if an IP address is private or reserved."""
    try:
        ip_bytes = socket.inet_aton(ip_str)
        ip_int = int.from_bytes(ip_bytes, 'big')

        # Check IPv4 private ranges
        for start, end in PRIVATE_IP_RANGES:
            if start <= ip_int <= end:
                return True

        # Check for localhost and other reserved IPs
        if ip_str in ('0.0.0.0', '255.255.255.255', '::1', '::'):
            return True

        # Check for IPv6 loopback
        if ':' in ip_str:
            # Basic check for IPv6 loopback
            if ip_str == '::1' or ip_str == '::ffff:127.0.0.1':
                return True
            # Check for ULA (fc00::/7) and link-local (fe80::/10) ranges
            if ip_str.startswith('fc') or ip_str.startswith('fd') or ip_str.startswith('fe80'):
                return True

        return False
    except socket.error:
        return True

def is_safe_domain(domain):
    """Validate domain against allowlist and IP restrictions."""
    # Only allow alphanumeric, hyphens, and dots
    if not re.match(r'^[a-zA-Z0-9.-]+$', domain):
        return False

    # Resolve domain to IP and check if it's private
    try:
        ip = socket.gethostbyname(domain)
        return not is_private_ip(ip)
    except socket.gaierror:
        return False

